#!/bin/bash
set -euo pipefail
cd /root/ARCARNA

mkdir -p "$(dirname 'client/src/pages/settings/developer.tsx')"
python3 - <<'PYEOF'
import base64, pathlib
p = pathlib.Path('client/src/pages/settings/developer.tsx')
p.write_bytes(base64.b64decode(''))
print('Wrote', p, 'bytes=', p.stat().st_size)
PYEOF

mkdir -p "$(dirname 'client/src/App.tsx')"
python3 - <<'PYEOF'
import base64, pathlib
p = pathlib.Path('client/src/App.tsx')
p.write_bytes(base64.b64decode(''))
print('Wrote', p, 'bytes=', p.stat().st_size)
PYEOF

mkdir -p "$(dirname 'client/src/components/nav-items.ts')"
python3 - <<'PYEOF'
import base64, pathlib
p = pathlib.Path('client/src/components/nav-items.ts')
p.write_bytes(base64.b64decode(''))
print('Wrote', p, 'bytes=', p.stat().st_size)
PYEOF

grep -n 'settings/developer' client/src/App.tsx
grep -n "key: 'developer'" client/src/components/nav-items.ts
npm run build
pm2 restart ARCARNA
echo 'Done — open https://viger.cloud/arcarna/settings/developer'
